import { test, expect } from '@playwright/test';
import { signInAs, openChannel, sendMessage, setDNDViaAPI } from './fixtures';

test('member in DND sees only badge increment — no banner, no sound', async ({ browser }) => {
  const aliceCtx = await browser.newContext();
  const bobCtx = await browser.newContext();
  const alice = await aliceCtx.newPage();
  const bob = await bobCtx.newPage();

  await signInAs(alice, 'alice');
  await signInAs(bob, 'bob');

  // Put bob in DND via API (manual toggle on).
  await setDNDViaAPI(bob, 'm_bob', true);

  await openChannel(alice, 'c1');
  // Open bob's home pane (where the unread badge surface is visible).
  await bob.click('[data-test=home-link]');
  await bob.waitForSelector('[data-test=channel-badge-c1]');

  // Capture the baseline badge count.
  const badgeBefore = await bob
    .locator('[data-test=channel-badge-c1]')
    .getAttribute('data-test-count');
  const beforeN = Number(badgeBefore ?? '0');

  // Alice mentions bob.
  await sendMessage(alice, '@m_bob ping');

  // Wait for badge to increment.
  await expect(async () => {
    const v = await bob
      .locator('[data-test=channel-badge-c1]')
      .getAttribute('data-test-count');
    expect(Number(v ?? '0')).toBe(beforeN + 1);
  }).toPass({ timeout: 5_000 });

  // Banner must NOT have appeared.
  const banner = bob.locator('[data-test=in-app-banner]');
  await expect(banner).toBeHidden();

  // Sound — exposed via the audio element with data-test=mention-sound. If
  // the implementation never appends/plays this element under DND, the
  // selector won't match.
  const sound = bob.locator('[data-test=mention-sound][data-test-status=played]');
  await expect(sound).toHaveCount(0);

  await aliceCtx.close();
  await bobCtx.close();
});
